using UnityEngine;

public class Functions : MonoBehaviour
{
    void Start()
    {
        // Calling methods
        int result = Add(5, 3);
        Debug.Log("5 + 3 = " + result);

        float damage = CalculateDamage(20, 10);
        Debug.Log("Damage: " + damage);

        string playerName = GetPlayerName();
        Debug.Log("Player: " + playerName);

        PrintMessage("Hello from a method!");

        // Method overloading
        Debug.Log("Overloaded: " + Multiply(3, 4));
        Debug.Log("Overloaded: " + Multiply(3, 4, 2));

        // Method with default parameters
        Debug.Log("Default: " + Greet("Hero"));
        Debug.Log("Default: " + Greet("Aragorn", "Elven"));
    }

    // Returns an int
    int Add(int a, int b)
    {
        return a + b;
    }

    // Returns a float
    float CalculateDamage(int attack, int defense)
    {
        float damage = attack - (defense * 0.5f);
        return Mathf.Max(damage, 1);  // At least 1 damage
    }

    // Returns a string
    string GetPlayerName()
    {
        return "Hero";
    }

    // Void method (returns nothing)
    void PrintMessage(string message)
    {
        Debug.Log(message);
    }

    // Overloaded method
    int Multiply(int a, int b)
    {
        return a * b;
    }

    int Multiply(int a, int b, int c)
    {
        return a * b * c;
    }

    // Method with default parameter
    string Greet(string name, string title = "Adventurer")
    {
        return title + " " + name;
    }
}

